class AMyProjectile : public AActor {
    GENERATED_BODY()
public:
    AMyProjectile() {
        SphereComp = CreateDefaultSubobject<USphereComponent>(TEXT("Sphere"));
        SetRootComponent(SphereComp);

        MeshComp = CreateDefaultSubobject<UStaticMeshComponent>(TEXT("Mesh"));
        MeshComp->SetupAttachment(SphereComp);

        ProjectileComp = CreateDefaultSubobject<UProjectileMovementComponent>(TEXT("Projectile"));

        SetLifeSpan(5.f); // Auto-destroy after 5 seconds
    }

    virtual void BeginPlay() override {
        Super::BeginPlay();
        SphereComp->OnComponentBeginOverlap.AddDynamic(this, &AMyProjectile::OnOverlap);
    }
};

