// Custom logic component — no transform needed
UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class UHealthComponent : public UActorComponent {
    GENERATED_BODY()
public:
    UHealthComponent() {
        PrimaryComponentTick.bCanEverTick = false; // No tick needed
    }

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    float MaxHealth = 100.f;

    UPROPERTY(BlueprintReadOnly)
    float CurrentHealth;

    UPROPERTY(BlueprintAssignable)
    FOnHealthChanged OnHealthChanged;

    virtual void BeginPlay() override {
        Super::BeginPlay();
        CurrentHealth = MaxHealth;
    }

    UFUNCTION(BlueprintCallable)
    void ApplyDamage(float Amount) {
        CurrentHealth = FMath::Clamp(CurrentHealth - Amount, 0.f, MaxHealth);
        OnHealthChanged.Broadcast(CurrentHealth, MaxHealth);
    }
};

// Scene component hierarchy in constructor
AMyActor::AMyActor() {
    // Root
    RootComp = CreateDefaultSubobject<USceneComponent>(TEXT("Root"));
    SetRootComponent(RootComp);

    // Mesh attached to root
    Mesh = CreateDefaultSubobject<UStaticMeshComponent>(TEXT("Mesh"));
    Mesh->SetupAttachment(RootComp);

    // Camera arm attached to root
    SpringArm = CreateDefaultSubobject<USpringArmComponent>(TEXT("Arm"));
    SpringArm->SetupAttachment(RootComp);
    SpringArm->TargetArmLength = 300.f;

    // Camera attached to arm
    Camera = CreateDefaultSubobject<UCameraComponent>(TEXT("Camera"));
    Camera->SetupAttachment(SpringArm);
}

