UCLASS()
class AMySpawner : public AActor {
    GENERATED_BODY()
public:
    // Designer picks which enemy class to spawn
    UPROPERTY(EditAnywhere, Category="Spawning")
    TSubclassOf<AEnemy> EnemyClass;

    // Soft reference — doesn't load until needed
    UPROPERTY(EditAnywhere, Category="Effects")
    TSoftObjectPtr<UParticleSystem> ExplosionEffect;

    void SpawnEnemy() {
        if (EnemyClass) {
            GetWorld()->SpawnActor<AEnemy>(EnemyClass, SpawnTransform);
        }
    }

    void PlayExplosion() {
        UParticleSystem* Loaded = ExplosionEffect.LoadSynchronous();
        if (Loaded) {
            UGameplayStatics::SpawnEmitterAtLocation(GetWorld(), Loaded, GetActorLocation());
        }
    }
};
